public sealed class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, ShipmentDetails> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["PKG-001"] = new ShipmentDetails(
            TrackingNumber: "PKG-001",
            Status: "In Transit",
            Location: "Chicago, IL",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 25, 17, 0, 0, TimeSpan.Zero),
            Updates: new List<StatusUpdate>
            {
                new("Package picked up", "New York, NY", new DateTimeOffset(2026, 5, 20, 9, 0, 0, TimeSpan.Zero)),
                new("Departed facility", "New York, NY", new DateTimeOffset(2026, 5, 20, 14, 30, 0, TimeSpan.Zero)),
                new("Arrived at sorting center", "Chicago, IL", new DateTimeOffset(2026, 5, 21, 6, 15, 0, TimeSpan.Zero)),
                new("In transit to destination", "Chicago, IL", new DateTimeOffset(2026, 5, 22, 8, 0, 0, TimeSpan.Zero)),
            }),

        ["PKG-002"] = new ShipmentDetails(
            TrackingNumber: "PKG-002",
            Status: "Delivered",
            Location: "San Francisco, CA",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 21, 12, 0, 0, TimeSpan.Zero),
            Updates: new List<StatusUpdate>
            {
                new("Package picked up", "Seattle, WA", new DateTimeOffset(2026, 5, 18, 10, 0, 0, TimeSpan.Zero)),
                new("In transit", "Portland, OR", new DateTimeOffset(2026, 5, 19, 7, 0, 0, TimeSpan.Zero)),
                new("Out for delivery", "San Francisco, CA", new DateTimeOffset(2026, 5, 21, 8, 0, 0, TimeSpan.Zero)),
                new("Delivered", "San Francisco, CA", new DateTimeOffset(2026, 5, 21, 11, 42, 0, TimeSpan.Zero)),
            }),

        ["PKG-003"] = new ShipmentDetails(
            TrackingNumber: "PKG-003",
            Status: "Processing",
            Location: "Dallas, TX",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 28, 15, 0, 0, TimeSpan.Zero),
            Updates: new List<StatusUpdate>
            {
                new("Label created", "Dallas, TX", new DateTimeOffset(2026, 5, 22, 7, 0, 0, TimeSpan.Zero)),
            }),
    };

    public async Task<ShipmentDetails?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        // Simulate slow backend
        await Task.Delay(1500, ct);

        SeedData.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

@page "/shipments/{TrackingNumber}"
@using sv_0272c71543cf4ac397ed1a5f59602ccd.Client.Models
@using sv_0272c71543cf4ac397ed1a5f59602ccd.Client.Services
@rendermode InteractiveAuto
@implements IDisposable
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="loading-placeholder">
        <p>Loading shipment details for <strong>@TrackingNumber</strong>...</p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="error-container">
        <p class="error-message">@_errorMessage</p>
        <button @onclick="RetryLoad">Retry</button>
    </div>
}
else if (_shipment is null)
{
    <div class="not-found">
        <p>No shipment found for tracking number <strong>@TrackingNumber</strong>.</p>
    </div>
}
else
{
    <div class="shipment-details">
        <h2>Shipment @_shipment.TrackingNumber</h2>
        <dl>
            <dt>Status</dt>
            <dd>@_shipment.Status</dd>
            <dt>Location</dt>
            <dd>@_shipment.Location</dd>
            <dt>Estimated Delivery</dt>
            <dd>@_shipment.EstimatedDelivery.ToString("f")</dd>
        </dl>

        <h3>Status Updates</h3>
        <ul class="status-updates">
            @foreach (var update in _shipment.Updates)
            {
                <li>
                    <strong>@update.Timestamp.ToString("g")</strong> —
                    @update.Description (@update.Location)
                </li>
            }
        </ul>
    </div>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = string.Empty;

    private ShipmentDetails? _shipment;
    private bool _loading;
    private string? _errorMessage;

    private CancellationTokenSource _cts = new();

    protected override async Task OnParametersSetAsync()
    {
        // Cancel any previous in-flight request when the route parameter changes
        await CancelPendingRequestAsync();
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        _loading = true;
        _errorMessage = null;
        _shipment = null;
        StateHasChanged();

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, _cts.Token);
        }
        catch (OperationCanceledException)
        {
            // Request was cancelled (navigation or disposal) — do nothing
            return;
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
            StateHasChanged();
        }
    }

    private async Task RetryLoad()
    {
        await CancelPendingRequestAsync();
        await LoadShipmentAsync();
    }

    private async Task CancelPendingRequestAsync()
    {
        await _cts.CancelAsync();
        _cts.Dispose();
        _cts = new CancellationTokenSource();
    }

    public void Dispose()
    {
        _cts.Cancel();
        _cts.Dispose();
    }
}

